{"code": "import json
import re
import os

# Load books data - the result is stored in a file
# Get the file path from the variable
books_file_path = var_functions.query_db_14

with open(books_file_path, 'r') as f:
    books_data = json.load(f)

# Create a simple analysis without pandas first
valid_books = []
for book in books_data:
    details = book.get('details')
    if details:
        match = re.search(r'\b(19\d{2}|20\d{2})\b', str(details))
        if match:
            year = int(match.group(1))
            decade = (year // 10) * 10
            valid_books.append({
                'book_id': book['book_id'],
                'year': year,
                'decade': decade
            })

# Count books by decade
decade_counts = {}
for book in valid_books:
    decade = book['decade']
    decade_counts[decade] = decade_counts.get(decade, 0) + 1

# Filter decades with at least 10 books
eligible_decades = {k: v for k, v in decade_counts.items() if v >= 10}

print('__RESULT__:')
print(json.dumps({
    'total_books_processed': len(books_data),
    'books_with_valid_year': len(valid_books),
    'decades_with_10plus_books': len(eligible_decades),
    'eligible_decades': sorted(eligible_decades.items())
}))"}

